esqlQuery.esql:
FROM metrics-generic.otel-default
| WHERE metrics.zookeeper.file_descriptor.open IS NOT NULL
  AND metrics.zookeeper.file_descriptor.limit IS NOT NULL
// Compute FD utilization as a percentage
| EVAL fd_pct = metrics.zookeeper.file_descriptor.open * 100.0
  / metrics.zookeeper.file_descriptor.limit
// Take the peak utilization per node in the time window
| STATS max_fd_pct = MAX(fd_pct) BY host.name
// 80% threshold — approaching the limit causes connection refusals
// Each client connection uses one FD plus FDs for data/transaction logs
// Adjust based on your configured FD limits
| WHERE max_fd_pct > 80
